38	// ── Session broadcast infrastructure ─────────────────────────────────
39	
40	/**
41	 * A single subscriber within a session broadcaster.
42	 * Chunks are queued here until the consumer iterates them.
43	 */
44	interface BroadcastSubscriber {
45	  queue: SessionChunk[];
46	  notify: (() => void) | null;
47	  done: boolean;
48	}
49	
50	/**
51	 * An in-process broadcast channel for a single running session.
52	 *
53	 * Multiple consumers can subscribe and each receives all chunks from the
54	 * beginning of the session (history replay) plus any future chunks.
55	 * When the session ends, all subscriptions complete.
56	 */
57	interface SessionBroadcaster {
58	  push(chunk: SessionChunk): void;
59	  close(): void;
60	  subscribe(): AsyncIterable<SessionChunk>;
61	}
62	
63	function createSessionBroadcaster(): SessionBroadcaster {
64	  const history: SessionChunk[] = [];
65	  const subscribers: BroadcastSubscriber[] = [];
66	  let closed = false;
67	
68	  function push(chunk: SessionChunk): void {
69	    history.push(chunk);
70	    for (const sub of subscribers) {
71	      if (!sub.done) {
72	        sub.queue.push(chunk);
73	        if (sub.notify) {
74	          const notify = sub.notify;
75	          sub.notify = null;
76	          notify();
77	        }
78	      }
79	    }
80	  }
81	
82	  function close(): void {
83	    closed = true;
84	    for (const sub of subscribers) {
85	      sub.done = true;
86	      if (sub.notify) {
87	        const notify = sub.notify;
88	        sub.notify = null;
89	        notify();
90	      }
91	    }
92	  }
93	
94	  function subscribe(): AsyncIterable<SessionChunk> {
95	    // New subscriber starts with full history replay, then receives future chunks.
96	    const sub: BroadcastSubscriber = {
97	      queue: [...history],
98	      notify: null,
99	      done: closed,
100	    };
101	    if (!closed) {
102	      subscribers.push(sub);
103	    }
104	    return {
105	      [Symbol.asyncIterator]() {
106	        return {
107	          async next() {
108	            while (sub.queue.length === 0 && !sub.done) {
109	              await new Promise<void>((resolve) => {
110	                sub.notify = resolve;
111	              });
112	            }
113	            if (sub.queue.length > 0) {
114	              return { value: sub.queue.shift()!, done: false as const };
115	            }
116	            return { value: undefined as unknown as SessionChunk, done: true as const };
117	          },
118	        };
119	      },
120	    };
121	  }
122	
123	  return { push, close, subscribe };
124	}
