128	/**
129	 * Resolve the session provider apparatus.
130	 *
131	 * Looks up the provider by plugin id from guild config. The provider is
132	 * an apparatus whose `provides` implements AnimatorSessionProvider.
133	 * Arbor throws immediately if the plugin isn't loaded or has no provides.
134	 */
135	function resolveProvider(config: AnimatorConfig): AnimatorSessionProvider {
136	  const pluginId = config.sessionProvider ?? 'claude-code';
137	  return guild().apparatus<AnimatorSessionProvider>(pluginId);
138	}
