149	/**
150	 * Build the provider config from an AnimateRequest.
151	 *
152	 * The system prompt comes from the AnimaWeave (composed by The Loom).
153	 * The work prompt comes from the request directly (bypasses The Loom).
154	 * The streaming flag is passed through for the provider to honor (or ignore).
155	 */
156	/**
157	 * Build a working-directory preamble that tells the agent where it is.
158	 *
159	 * Claude Code tools (Glob, Grep) return relative paths; the agent must
160	 * construct absolute paths for Read/Edit/Write. Without an explicit
161	 * preamble the agent guesses — and when other checkouts exist on the
162	 * filesystem (e.g. /workspace/nexus/) it routinely guesses wrong,
163	 * committing to the persistent clone instead of its worktree.
164	 */
165	function cwdPreamble(cwd: string): string {
166	  return [
167	    `Your working directory is: ${cwd}`,
168	    'All file operations (Read, Edit, Write, Glob, Grep) must use paths rooted in this directory.',
169	    'Do NOT read, write, or explore files outside this directory.',
170	    '',
171	  ].join('\n');
172	}
173	
174	function buildProviderConfig(
175	  request: AnimateRequest,
176	  model: string,
177	  sessionId: string,
178	): SessionProviderConfig {
179	  // Prepend cwd preamble to the initial prompt so the agent knows where
180	  // it is. Skip for resumed conversations — the preamble was already
181	  // delivered in the original session's first message.
182	  const prompt = request.conversationId
183	    ? request.prompt
184	    : cwdPreamble(request.cwd) + (request.prompt ?? '');
185	
186	  return {
187	    sessionId,
188	    systemPrompt: request.context.systemPrompt,
189	    initialPrompt: prompt,
190	    model,
191	    conversationId: request.conversationId,
192	    cwd: request.cwd,
193	    streaming: request.streaming,
194	    tools: request.context.tools,
195	    environment: { ...request.context.environment, ...request.environment },
196	  };
197	}
