199	/**
200	 * Build a SessionResult from provider output and session metadata.
201	 */
202	function buildSessionResult(
203	  id: string,
204	  startedAt: string,
205	  providerName: string,
206	  providerResult: SessionProviderResult,
207	  request: AnimateRequest,
208	): SessionResult {
209	  const endedAt = new Date().toISOString();
210	  const durationMs = new Date(endedAt).getTime() - new Date(startedAt).getTime();
211	
212	  return {
213	    id,
214	    status: providerResult.status,
215	    startedAt,
216	    endedAt,
217	    durationMs,
218	    provider: providerName,
219	    exitCode: providerResult.exitCode,
220	    error: providerResult.error,
221	    // For the first session in a conversation chain, promote the
222	    // provider's session id to conversationId so downstream sessions
223	    // can resume via --resume. When the request already carries a
224	    // conversationId (resumed session), preserve it as-is.
225	    conversationId: request.conversationId ?? providerResult.providerSessionId,
226	    providerSessionId: providerResult.providerSessionId,
227	    tokenUsage: providerResult.tokenUsage,
228	    costUsd: providerResult.costUsd,
229	    metadata: request.metadata,
230	    output: providerResult.output,
231	  };
232	}
