238	  id: string,
239	  startedAt: string,
240	  providerName: string,
241	  error: unknown,
242	  request: AnimateRequest,
243	): SessionResult {
244	  const endedAt = new Date().toISOString();
245	  const durationMs = new Date(endedAt).getTime() - new Date(startedAt).getTime();
246	  const errorMessage = error instanceof Error ? error.message : String(error);
247	
248	  return {
249	    id,
250	    status: 'failed',
251	    startedAt,
252	    endedAt,
253	    durationMs,
254	    provider: providerName,
255	    exitCode: 1,
256	    error: errorMessage,
257	    conversationId: request.conversationId,
258	    metadata: request.metadata,
259	  };
260	}
