284	/**
285	 * Record a session result to The Stacks (sessions + transcripts books).
286	 *
287	 * Errors are logged but never propagated — session data loss is
288	 * preferable to masking the original failure. See § Error Handling Contract.
289	 */
290	async function recordSession(
291	  sessions: Book<SessionDoc>,
292	  transcripts: Book<TranscriptDoc>,
293	  result: SessionResult,
294	  transcript: TranscriptMessage[] | undefined,
295	): Promise<void> {
296	  try {
297	    await sessions.put(toSessionDoc(result));
298	  } catch (err) {
299	    console.warn(
300	      `[animator] Failed to record session ${result.id}: ${err instanceof Error ? err.message : err}`,
301	    );
302	  }
303	
304	  if (transcript && transcript.length > 0) {
305	    try {
306	      await transcripts.put({ id: result.id, messages: transcript });
307	    } catch (err) {
308	      console.warn(
309	        `[animator] Failed to record transcript for ${result.id}: ${err instanceof Error ? err.message : err}`,
310	      );
311	    }
312	  }
313	}
