315	/**
316	 * Write the initial 'running' session record to The Stacks.
317	 */
318	async function recordRunning(
319	  sessions: Book<SessionDoc>,
320	  id: string,
321	  startedAt: string,
322	  providerName: string,
323	  request: AnimateRequest,
324	  cancelHandle?: Record<string, unknown>,
325	): Promise<void> {
326	  try {
327	    // Merge with any pre-existing doc (e.g. `pending` pre-written by
328	    // launchDetached, or `running` already written by the babysitter via
329	    // the session-running tool). Preserve authorizedTools and other
330	    // fields the caller may not have passed.
331	    const existing = await sessions.get(id);
332	    const merged: SessionDoc = {
333	      ...(existing ?? {}),
334	      id,
335	      status: 'running',
336	      startedAt: existing?.startedAt ?? startedAt,
337	      provider: existing?.provider ?? providerName,
338	    };
339	    if (request.conversationId !== undefined) {
340	      merged.conversationId = request.conversationId;
341	    } else if (existing?.conversationId !== undefined) {
342	      merged.conversationId = existing.conversationId;
343	    }
344	    if (request.metadata !== undefined || existing?.metadata !== undefined) {
345	      merged.metadata = { ...(existing?.metadata ?? {}), ...(request.metadata ?? {}) };
346	    }
347	    if (cancelHandle !== undefined) {
348	      merged.cancelHandle = { ...(existing?.cancelHandle ?? {}), ...cancelHandle };
349	    }
350	    await sessions.put(merged);
351	  } catch (err) {
352	    console.warn(
353	      `[animator] Failed to write initial session record ${id}: ${err instanceof Error ? err.message : err}`,
354	    );
355	  }
356	}
357	
358	/** Terminal status values — any of these means the session is done. */
359	const TERMINAL_STATUSES = new Set(['completed', 'failed', 'timeout', 'cancelled']);
360	
361	// ── Apparatus factory ────────────────────────────────────────────────
362	
363	/**
364	 * Create the Animator apparatus plugin.
365	 *
366	 * Returns a Plugin with:
367	 * - `requires: ['stacks']` — records session results
368	 * - `provides: AnimatorApi` — the session launch API
369	 * - `supportKit` — contributes `sessions` book + inspection tools
370	 */
371	export function createAnimator(): Plugin {
372	  let config: AnimatorConfig = {};
373	  let sessions: Book<SessionDoc>;
374	  let transcripts: Book<TranscriptDoc>;
375	
376	  /**
377	   * In-memory registry of active session broadcasters.
378	   * Keyed by session id. Entries are removed ~30 s after the session ends,
379	   * which gives late SSE subscribers time to drain any buffered chunks.
380	   */
381	  const activeSessions = new Map<string, SessionBroadcaster>();
382	
383	  const api: AnimatorApi = {
384	    subscribeToSession(sessionId: string): AsyncIterable<SessionChunk> | null {
385	      const broadcaster = activeSessions.get(sessionId);
386	      if (!broadcaster) return null;
387	      return broadcaster.subscribe();
388	    },
389	
390	    async cancel(sessionId: string, options?: { reason?: string }): Promise<SessionDoc> {
391	      // Step 1: Read current SessionDoc
392	      const doc = await sessions.get(sessionId);
393	      if (!doc) {
394	        throw new Error(`Session "${sessionId}" not found.`);
395	      }
396	
397	      // Idempotent: if already terminal, return as-is
398	      if (TERMINAL_STATUSES.has(doc.status)) {
399	        return doc;
400	      }
401	
402	      // Step 2: Patch to cancelled
403	      const endedAt = new Date().toISOString();
404	      const durationMs = new Date(endedAt).getTime() - new Date(doc.startedAt).getTime();
405	
406	      const updated: SessionDoc = {
407	        ...doc,
408	        status: 'cancelled',
409	        endedAt,
410	        durationMs,
411	        ...(options?.reason ? { error: options.reason } : {}),
412	      };
413	
414	      try {
415	        await sessions.put(updated);
416	      } catch (err) {
417	        console.warn(
418	          `[animator] Failed to patch session ${sessionId} to cancelled: ${err instanceof Error ? err.message : err}`,
419	        );
420	      }
421	
422	      // Step 3: If cancelHandle available, delegate to provider
423	      if (doc.cancelHandle) {
424	        try {
425	          const prov = resolveProvider(config);
426	          if (prov.cancel) {
427	            await prov.cancel(doc.cancelHandle);
428	          }
429	        } catch (err) {
430	          console.warn(
431	            `[animator] Failed to cancel provider process for ${sessionId}: ${err instanceof Error ? err.message : err}`,
432	          );
433	        }
434	      }
435	
436	      return updated;
437	    },
438	
439	    summon(request: SummonRequest): AnimateHandle {
440	      // Resolve The Loom at call time — not a startup dependency.
441	      // This allows the Animator to start without the Loom installed;
442	      // only summon() requires it.
443	      let loom: LoomApi;
444	      try {
445	        loom = guild().apparatus<LoomApi>('loom');
446	      } catch {
447	        throw new Error(
448	          'summon() requires The Loom apparatus to be installed. ' +
449	          'Use animate() directly if you want to provide a pre-composed AnimaWeave.',
450	        );
451	      }
452	
453	      // Generate session id up front so it's available on the handle
454	      // immediately — before the Loom weave or session launch resolves.
455	      const sessionId = generateId('ses', 4);
456	
457	      // We need to weave context before we can animate, but summon()
458	      // must return synchronously. Wrap the async Loom call and the
459	      // animate delegation into a single deferred flow.
460	      const deferred = (async () => {
461	        // Compose identity context via The Loom.
462	        // The Loom owns system prompt composition — it produces the system
463	        // prompt from the anima's identity layers (role instructions,
464	        // curriculum, temperament, charter). MVP: returns empty (no
465	        // systemPrompt); the session runs without one until the Loom
466	        // gains composition logic. The work prompt bypasses the Loom.
467	        const context = await loom.weave({
468	          role: request.role,
469	        });
470	
471	        // Merge caller metadata with auto-generated summon metadata
472	        const metadata: Record<string, unknown> = {
473	          trigger: 'summon',
474	          ...(request.role ? { role: request.role } : {}),
475	          ...request.metadata,
476	        };
477	
478	        // Delegate to the standard animate path, threading through the
479	        // pre-generated session id so animate() uses it instead of
480	        // generating a new one.
481	        return this.animate({
482	          sessionId,
483	          context,
484	          prompt: request.prompt,
485	          cwd: request.cwd,
486	          conversationId: request.conversationId,
487	          metadata,
488	          streaming: request.streaming,
489	          environment: request.environment,
490	        });
491	      })();
492	
493	      // Pipe chunks through — can't get them until the Loom weave resolves.
494	      // Works for both streaming and non-streaming: non-streaming providers
495	      // return empty chunks, so the generator yields nothing and completes.
496	      async function* pipeChunks(): AsyncIterable<SessionChunk> {
497	        const handle = await deferred;
498	        yield* handle.chunks;
499	      }
500	
501	      return {
502	        sessionId,
503	        chunks: pipeChunks(),
504	        result: deferred.then((handle) => handle.result),
505	      };
506	    },
507	
508	    animate(request: AnimateRequest): AnimateHandle {
509	      const provider = resolveProvider(config);
510	      const model = resolveModel();
511	
512	      // Step 1: use pre-generated session id if provided (from summon()),
513	      // otherwise generate one. Capture startedAt.
514	      const id = request.sessionId ?? generateId('ses', 4);
515	      const startedAt = new Date().toISOString();
516	
517	      const providerConfig = buildProviderConfig(request, model, id);
518	
519	      // Single path — the provider returns { chunks, result } regardless
520	      // of whether streaming is enabled. Providers that don't support
521	      // streaming return empty chunks; the Animator doesn't branch.
522	      const { chunks: providerChunks, result: providerResultPromise, processInfo: processInfoPromise } = provider.launch(providerConfig);
523	
524	      // Set up an in-process broadcaster for this session.
525	      // All chunks are fanned out through the broadcaster so that both the
526	      // returned handle.chunks and any subscribeToSession() callers receive
527	      // the full stream with history replay for late subscribers.
528	      const broadcaster = createSessionBroadcaster();
529	      activeSessions.set(id, broadcaster);
530	
531	      // Consume provider chunks in the background and push to the broadcaster.
532	      // This drives the fan-out to all subscribers (including handle.chunks).
533	      (async () => {
534	        try {
535	          for await (const chunk of providerChunks) {
536	            broadcaster.push(chunk);
537	          }
538	        } catch (err) {
539	          console.warn(
540	            `[animator] Error consuming chunks for session ${id}: ${err instanceof Error ? err.message : err}`,
541	          );
542	        } finally {
543	          broadcaster.close();
544	        }
545	      })();
546	
547	      // Write initial record (fire and forget — don't block streaming).
548	      // Await processInfo so cancelHandle is persisted with the running record.
549	      const initPromise = (async () => {
550	        let cancelHandle: Record<string, unknown> | undefined;
551	        if (processInfoPromise) {
552	          try {
553	            cancelHandle = await processInfoPromise;
554	          } catch (err) {
555	            console.warn(`[animator] Failed to get processInfo for ${id}: ${err instanceof Error ? err.message : err}`);
556	          }
557	        }
558	        await recordRunning(sessions, id, startedAt, provider.name, request, cancelHandle);
559	      })();
560	
561	      const result = (async () => {
562	        await initPromise;
563	
564	        let sessionResult: SessionResult;
565	        try {
566	          const providerResult = await providerResultPromise;
567	
568	          // Check if the session was cancelled (by this process or another)
569	          // before overwriting the SessionDoc.
570	          const currentDoc = await sessions.get(id);
571	          if (currentDoc?.status === 'cancelled') {
572	            // Session was cancelled — don't overwrite the doc.
573	            // Write partial transcript if available.
574	            if (providerResult.transcript && providerResult.transcript.length > 0) {
575	              try {
576	                await transcripts.put({ id, messages: providerResult.transcript });
577	              } catch (err) {
578	                console.warn(
579	                  `[animator] Failed to record transcript for cancelled session ${id}: ${err instanceof Error ? err.message : err}`,
580	                );
581	              }
582	            }
583	            // Resolve with cancelled status, preserving endedAt/durationMs from the doc.
584	            sessionResult = {
585	              id,
586	              status: 'cancelled',
587	              startedAt,
588	              endedAt: currentDoc.endedAt ?? new Date().toISOString(),
589	              durationMs: currentDoc.durationMs ?? (Date.now() - new Date(startedAt).getTime()),
590	              provider: provider.name,
591	              exitCode: providerResult.exitCode,
592	              error: currentDoc.error,
593	              conversationId: request.conversationId,
594	              providerSessionId: providerResult.providerSessionId,
595	              tokenUsage: providerResult.tokenUsage,
596	              costUsd: providerResult.costUsd,
597	              metadata: request.metadata,
598	              output: providerResult.output,
599	            };
600	            return sessionResult;
601	          }
602	
603	          sessionResult = buildSessionResult(id, startedAt, provider.name, providerResult, request);
604	          await recordSession(sessions, transcripts, sessionResult, providerResult.transcript);
605	        } catch (err) {
606	          // Check if session was cancelled — if so, resolve instead of rejecting.
607	          const currentDoc = await sessions.get(id);
608	          if (currentDoc?.status === 'cancelled') {
609	            sessionResult = {
610	              id,
611	              status: 'cancelled',
612	              startedAt,
613	              endedAt: currentDoc.endedAt ?? new Date().toISOString(),
614	              durationMs: currentDoc.durationMs ?? (Date.now() - new Date(startedAt).getTime()),
615	              provider: provider.name,
616	              exitCode: 1,
617	              error: currentDoc.error,
618	              conversationId: request.conversationId,
619	              metadata: request.metadata,
620	            };
621	            return sessionResult;
622	          }
623	
624	          sessionResult = buildFailedResult(id, startedAt, provider.name, err, request);
625	          await recordSession(sessions, transcripts, sessionResult, undefined);
626	          throw err;
627	        } finally {
628	          // Remove the broadcaster after a short delay so that any late-connecting
629	          // SSE subscribers can still drain buffered chunks before the entry disappears.
630	          setTimeout(() => activeSessions.delete(id), 30_000);
631	        }
632	        return sessionResult;
633	      })();
634	
635	      // The handle's chunks is a broadcaster subscription, providing history
636	      // replay and real-time delivery for this session's caller.
637	      return { sessionId: id, chunks: broadcaster.subscribe(), result };
638	    },
639	  };
640	
641	  return {
642	    apparatus: {
643	      requires: ['stacks'],
644	      recommends: ['loom', 'oculus'],
645	
646	      supportKit: {
647	        books: {
648	          sessions: {
649	            indexes: ['startedAt', 'status', 'conversationId', 'provider'],
650	          },
651	          transcripts: {
652	            indexes: ['sessionId'],
653	          },
654	          state: {},
655	        },
656	        tools: [sessionList, sessionShow, summonTool, sessionCancel, sessionRunning, sessionRecord, sessionHeartbeat],
657	        pages: [
658	          { id: 'animator', title: 'Animator', dir: 'src/static' },
659	        ],
660	        routes: animatorRoutes,
661	      },
662	
663	      provides: api,
664	
665	      start(_ctx: StartupContext): void {
666	        const g = guild();
667	        config = g.guildConfig().animator ?? {};
668	
669	        const stacks = g.apparatus<StacksApi>('stacks');
670	        sessions = stacks.book<SessionDoc>('animator', 'sessions');
671	        transcripts = stacks.book<TranscriptDoc>('animator', 'transcripts');
672	
673	        const GUILD_HEARTBEAT_INTERVAL_MS = 30_000;
674	        const GUILD_HEARTBEAT_DOC_ID = 'guild-heartbeat';
675	        const RECONCILER_INTERVAL_MS = 30_000;
676	
677	        const state = stacks.book<GuildStateDoc>('animator', 'state');
678	
679	        // IMPORTANT: DLQ drain MUST complete before orphan recovery.
680	        // DLQ files contain real terminal results from babysitters that couldn't
681	        // reach the guild. If the reconciler runs first, it sees those sessions as
682	        // stale (no recent heartbeat) and marks them failed — losing the real result.
683	        // drainDlq() applies the correct terminal status; recoverOrphans() then
684	        // correctly skips them as already-terminal.
685	        (async () => {
686	          try {
687	            await drainDlq(g.home);
688	          } catch (err) {
689	            console.warn(
690	              `[animator] DLQ drain failed: ${err instanceof Error ? err.message : err}`,
691	            );
692	          }
693	
694	          // Compute downtime credit from the gap between previous guild_alive_at and now.
695	          let downtimeCredit = 0;
696	          try {
697	            const prev = await state.get(GUILD_HEARTBEAT_DOC_ID);
698	            if (prev?.guildAliveAt) {
699	              const gap = Date.now() - new Date(prev.guildAliveAt).getTime();
700	              downtimeCredit = Math.max(0, gap - GUILD_HEARTBEAT_INTERVAL_MS);
701	            }
702	          } catch { /* fresh install — no credit */ }
703	
704	          // Write the initial guild_alive_at.
705	          try {
706	            await state.put({ id: GUILD_HEARTBEAT_DOC_ID, guildAliveAt: new Date().toISOString() });
707	          } catch (err) {
708	            console.warn(
709	              `[animator] Failed to write initial guild_alive_at: ${err instanceof Error ? err.message : err}`,
710	            );
711	          }
712	
713	          // Run initial reconciler with downtime credit.
714	          try {
715	            await recoverOrphans(sessions, downtimeCredit);
716	          } catch (err) {
717	            console.warn(
718	              `[animator] Orphan recovery failed: ${err instanceof Error ? err.message : err}`,
719	            );
720	          }
721	        })();
722	
723	        // Guild self-heartbeat timer — updates guild_alive_at every 30s.
724	        const guildHeartbeatTimer = setInterval(async () => {
725	          try {
726	            await state.put({ id: GUILD_HEARTBEAT_DOC_ID, guildAliveAt: new Date().toISOString() });
727	          } catch (err) {
728	            console.warn(`[animator] Failed to update guild_alive_at: ${err instanceof Error ? err.message : err}`);
729	          }
730	        }, GUILD_HEARTBEAT_INTERVAL_MS);
731	        guildHeartbeatTimer.unref();
732	
733	        // Periodic reconciler — runs every 30s with no downtime credit.
734	        let reconciling = false;
735	        const reconcilerTimer = setInterval(async () => {
736	          if (reconciling) return;
737	          reconciling = true;
738	          try {
739	            await recoverOrphans(sessions, 0);
740	          } catch (err) {
