1	/**
2	 * Session Babysitter — detached process that hosts a claude session.
3	 *
4	 * A standalone Node.js script that:
5	 * 1. Reads config from stdin (spawned by the claude-code provider)
6	 * 2. Opens the guild's SQLite database for transcript streaming
7	 * 3. Starts an MCP/SSE server that proxies tool calls to the guild
8	 * 4. Spawns claude with prepared session files
9	 * 5. Reports session lifecycle events via the guild's HTTP API
10	 * 6. Streams transcript data to SQLite in real-time
11	 * 7. Reports the final result and cleans up
12	 *
13	 * The babysitter is a detached process: it survives guild restarts.
14	 * All guild communication is via HTTP (tool server) and SQLite (transcripts).
15	 *
16	 * See: docs/architecture/detached-sessions.md
17	 */
18	
19	import { spawn, type ChildProcess } from 'node:child_process';
20	import fs from 'node:fs';
21	import os from 'node:os';
22	import path from 'node:path';
23	import http from 'node:http';
24	import { fileURLToPath } from 'node:url';
25	
26	import { Server } from '@modelcontextprotocol/sdk/server/index.js';
27	import {
28	  ListToolsRequestSchema,
29	  CallToolRequestSchema,
30	} from '@modelcontextprotocol/sdk/types.js';
31	import { SSEServerTransport } from '@modelcontextprotocol/sdk/server/sse.js';
32	
33	import { toolNameToRoute } from '@shardworks/tools-apparatus';
34	
35	import {
36	  processNdjsonBuffer,
37	  parseStreamJsonMessage,
38	  extractFinalAssistantText,
39	  type StreamJsonResult,
40	} from './index.ts';
41	
42	// ── Config types ────────────────────────────────────────────────────────
43	
44	/** A serialized tool definition as received in the babysitter config. */
45	export interface SerializedTool {
46	  /** Tool name (e.g. 'writ-list'). */
47	  name: string;
48	  /** Tool description. */
49	  description: string;
50	  /** JSON Schema for the tool's input parameters. */
51	  params: Record<string, unknown>;
52	  /**
53	   * HTTP method the guild tool server routes this tool under. The MCP proxy
54	   * uses this to avoid POSTing to a GET-only read-tool route (which would
55	   * 404). Derived from the tool's `permission` by `permissionToMethod()`.
56	   */
57	  method: 'GET' | 'POST' | 'DELETE';
58	}
59	
60	/** Config written to the babysitter's stdin by the spawning process. */
61	export interface BabysitterConfig {
62	  sessionId: string;
63	  guildToolUrl: string;
64	  dbPath: string;
65	  logDir: string;
66	  claudeArgs: string[];
67	  cwd: string;
68	  env: Record<string, string>;
69	  prompt: string;
70	  tools: SerializedTool[];
71	  startedAt: string;
72	  provider: string;
73	  metadata?: Record<string, unknown>;
74	  /** Temp directory for the system prompt file. Cleaned up in finally block. */
75	  systemPromptTmpDir?: string;
76	}
77	
78	// ── Retry constants ─────────────────────────────────────────────────────
79	
80	const RETRY_INITIAL_DELAY_MS = 1_000;
81	const RETRY_MAX_DELAY_MS = 8_000;
82	const RETRY_TIMEOUT_MS = 60_000;
83	const RETRYABLE_CODES = new Set(['ECONNREFUSED', 'ECONNRESET', 'ETIMEDOUT']);
84	
85	/**
86	 * Walk an error's cause chain looking for a retryable error code.
87	 * Returns the first retryable code found, or null if none.
88	 * Caps traversal depth to prevent infinite loops from circular cause chains.
89	 */
90	export function findRetryableCode(err: unknown, maxDepth: number = 5): string | null {
91	  let current: unknown = err;
92	  for (let i = 0; i < maxDepth && current != null; i++) {
93	    const code = (current as NodeJS.ErrnoException).code;
94	    if (code && RETRYABLE_CODES.has(code)) {
95	      return code;
96	    }
97	    current = (current as Error).cause;
98	  }
99	  return null;
100	}
101	
102	// ── Public types ────────────────────────────────────────────────────────
103	
104	export interface McpProxyHandle {
105	  /** URL for --mcp-config (e.g. "http://127.0.0.1:PORT/sse"). */
106	  url: string;
107	  /** Shut down the HTTP server and MCP transport. */
108	  close(): Promise<void>;
109	}
110	
111	// ── stdin config reader ─────────────────────────────────────────────────
112	
113	/**
114	 * Read the babysitter config from stdin.
115	 *
116	 * Reads stdin to completion, parses the JSON, and validates required fields.
117	 * The spawning process writes config and closes the write end.
118	 */
119	export async function readConfigFromStdin(
120	  stream: NodeJS.ReadableStream = process.stdin,
121	): Promise<BabysitterConfig> {
122	  const chunks: Buffer[] = [];
123	
124	  for await (const chunk of stream) {
125	    chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk as string));
126	  }
127	
128	  const raw = Buffer.concat(chunks).toString('utf-8');
129	  if (!raw.trim()) {
130	    throw new Error('Empty config received on stdin');
131	  }
132	
133	  let parsed: unknown;
134	  try {
135	    parsed = JSON.parse(raw);
136	  } catch {
137	    throw new Error(`Invalid JSON config on stdin: ${raw.slice(0, 200)}`);
138	  }
139	
140	  const config = parsed as BabysitterConfig;
141	
142	  // Validate required fields
143	  const required: (keyof BabysitterConfig)[] = [
144	    'sessionId', 'guildToolUrl', 'dbPath', 'logDir', 'claudeArgs',
145	    'cwd', 'env', 'prompt', 'tools', 'startedAt', 'provider',
146	  ];
147	  for (const field of required) {
148	    if (config[field] === undefined || config[field] === null) {
149	      throw new Error(`Missing required config field: ${field}`);
150	    }
151	  }
152	
153	  return config;
154	}
155	
156	// ── HTTP retry helper ───────────────────────────────────────────────────
157	
158	/**
159	 * Call a guild HTTP API endpoint with exponential backoff retry.
160	 *
161	 * Retries on connection errors (ECONNREFUSED, ECONNRESET, ETIMEDOUT).
162	 * Returns the parsed JSON response on success.
163	 * Throws after RETRY_TIMEOUT_MS of retrying.
164	 */
165	/**
166	 * Encode a params object as a query string for GET requests.
167	 *
168	 * Scalars (string/number/boolean) become their string form. Arrays and
169	 * objects are JSON-encoded so the tool-server can still parse them after
170	 * its param coercion pass (though read-tools generally take scalar
171	 * inputs). null/undefined values are skipped.
172	 */
173	function encodeParamsAsQuery(params: unknown): string {
174	  if (params == null || typeof params !== 'object') return '';
175	  const usp = new URLSearchParams();
176	  for (const [key, value] of Object.entries(params as Record<string, unknown>)) {
177	    if (value == null) continue;
178	    if (typeof value === 'string') {
179	      usp.set(key, value);
180	    } else if (typeof value === 'number' || typeof value === 'boolean') {
181	      usp.set(key, String(value));
182	    } else {
183	      usp.set(key, JSON.stringify(value));
184	    }
185	  }
186	  const s = usp.toString();
187	  return s.length > 0 ? `?${s}` : '';
188	}
189	
190	export async function callGuildHttpApi(
191	  url: string,
192	  sessionId: string,
193	  body: unknown,
194	  timeoutMs: number = RETRY_TIMEOUT_MS,
195	  method: 'GET' | 'POST' | 'DELETE' = 'POST',
196	): Promise<unknown> {
197	  const startTime = Date.now();
198	  let delay = RETRY_INITIAL_DELAY_MS;
199	  let lastError: Error | undefined;
200	
201	  // GET can't carry a body — encode params as query string instead.
202	  const targetUrl = method === 'GET' ? `${url}${encodeParamsAsQuery(body)}` : url;
203	  const requestBody = method === 'GET' ? undefined : JSON.stringify(body);
204	
205	  while (Date.now() - startTime < timeoutMs) {
206	    try {
207	      const response = await fetch(targetUrl, {
208	        method,
209	        headers: {
210	          'Content-Type': 'application/json',
211	          'X-Session-Id': sessionId,
212	        },
213	        ...(requestBody !== undefined ? { body: requestBody } : {}),
214	      });
215	
216	      if (!response.ok) {
217	        const text = await response.text().catch(() => '');
218	        throw new Error(`HTTP ${response.status}: ${text.slice(0, 500)}`);
219	      }
220	
221	      return await response.json();
222	    } catch (err) {
223	      lastError = err instanceof Error ? err : new Error(String(err));
224	
225	      // Check if the error is retryable (connection-level error in the cause chain)
226	      const isRetryable = findRetryableCode(err) !== null;
227	
228	      if (!isRetryable) {
229	        throw lastError;
230	      }
231	
232	      // Wait before retrying
233	      const remaining = timeoutMs - (Date.now() - startTime);
234	      if (remaining <= 0) break;
235	
236	      await new Promise((resolve) => setTimeout(resolve, Math.min(delay, remaining)));
237	      delay = Math.min(delay * 2, RETRY_MAX_DELAY_MS);
238	    }
239	  }
240	
241	  throw new Error(
242	    `Guild HTTP API unreachable after ${timeoutMs}ms: ${lastError?.message ?? 'unknown error'}`,
243	  );
244	}
245	
246	// ── DLQ writer ──────────────────────────────────────────────────────────
247	
248	/**
249	 * Write a payload to the Dead Letter Queue.
250	 *
251	 * Creates the DLQ directory if it doesn't exist. Writes the payload as
252	 * pretty-printed JSON. Used as a fallback when the guild HTTP API is
253	 * unreachable for lifecycle calls.
254	 */
255	export function writeToDlq(cwd: string, filename: string, payload: unknown): void {
256	  const dlqDir = path.join(cwd, '.nexus', 'dlq');
257	  fs.mkdirSync(dlqDir, { recursive: true });
258	  fs.writeFileSync(
259	    path.join(dlqDir, filename),
260	    JSON.stringify(payload, null, 2),
261	  );
262	}
263	
264	// ── MCP proxy server ────────────────────────────────────────────────────
265	
266	/**
267	 * Create an MCP/SSE HTTP server that proxies tool calls to the guild.
268	 *
269	 * For each tool in the config, registers an MCP tool whose handler
270	 * forwards the call to the guild's Tool HTTP API via HTTP POST.
271	 *
272	 * Uses the low-level MCP Server class to register tools with raw
273	 * JSON Schema (the serialized params from the config).
274	 */
275	export async function createProxyMcpHttpServer(
276	  tools: SerializedTool[],
277	  guildToolUrl: string,
278	  sessionId: string,
279	): Promise<McpProxyHandle> {
280	  const server = new Server(
281	    { name: 'nexus-guild-proxy', version: '0.0.0' },
282	    { capabilities: { tools: {} } },
283	  );
284	
285	  // ── MCP proxy diagnostics ──────────────────────────────────────────
286	  // Track connection state and tool call metrics for debugging SSE drops.
287	  let sseConnectedAt: number | null = null;
288	  let sseClosedAt: number | null = null;
289	  let toolCallCount = 0;
290	
291	  // Register tools/list handler — advertises all tools with their JSON Schema.
292	  server.setRequestHandler(ListToolsRequestSchema, async () => ({
293	    tools: tools.map((t) => ({
294	      name: t.name,
295	      description: t.description,
296	      inputSchema: {
297	        type: 'object' as const,
298	        ...t.params,
299	      },
300	    })),
301	  }));
302	
303	  // Build a name → HTTP method lookup so the proxy can route each call to
304	  // the correct verb (read tools are GET-only on the tool server; POSTing
305	  // to them 404s).
306	  const toolMethods = new Map<string, 'GET' | 'POST' | 'DELETE'>();
307	  for (const t of tools) {
308	    toolMethods.set(t.name, t.method);
309	  }
310	
311	  // Register tools/call handler — proxies each call to the guild HTTP API.
312	  server.setRequestHandler(CallToolRequestSchema, async (request) => {
313	    const toolName = request.params.name;
314	    const params = request.params.arguments ?? {};
315	
316	    const route = toolNameToRoute(toolName);
317	    const url = `${guildToolUrl}${route}`;
318	    const method = toolMethods.get(toolName) ?? 'POST';
319	
320	    toolCallCount++;
321	    const callNum = toolCallCount;
322	    const callStart = Date.now();
323	
324	    try {
325	      const result = await callGuildHttpApi(url, sessionId, params, undefined, method);
326	      const elapsed = Date.now() - callStart;
327	      process.stderr.write(`[babysitter] mcp-proxy: ${toolName} → ${method} ${route} (${elapsed}ms, call #${callNum})\n`);
328	      const text = typeof result === 'string' ? result : JSON.stringify(result, null, 2);
329	      return {
330	        content: [{ type: 'text' as const, text }],
331	      };
332	    } catch (err) {
333	      const elapsed = Date.now() - callStart;
334	      const message = err instanceof Error ? err.message : String(err);
335	      process.stderr.write(`[babysitter] mcp-proxy: ${toolName} FAILED (${elapsed}ms, call #${callNum}): ${message}\n`);
336	      return {
337	        content: [{ type: 'text' as const, text: `Error: ${message}` }],
338	        isError: true,
339	      };
340	    }
341	  });
342	
343	  // Wrap in HTTP server with SSE transport (same pattern as mcp-server.ts).
344	  // Promise-gate: POST /message waits for the SSE transport to be fully connected,
345	  // eliminating the race where a POST arrives before GET /sse completes.
346	  let resolveTransport!: (t: SSEServerTransport) => void;
347	  let rejectTransport!: (err: Error) => void;
348	  const transportReady = new Promise<SSEServerTransport>((resolve, reject) => {
349	    resolveTransport = resolve;
350	    rejectTransport = reject;
351	  });
352	
353	  // Direct reference for close() — null until connected.
354	  let transport: SSEServerTransport | null = null;
355	
356	  // SSE keepalive timer — sends periodic comments to prevent idle timeouts.
357	  // SSE spec says lines starting with ':' are comments, ignored by clients.
358	  const SSE_KEEPALIVE_INTERVAL_MS = 30_000;
359	  let keepaliveTimer: ReturnType<typeof setInterval> | null = null;
360	
361	  const httpServer = http.createServer(async (req, res) => {
362	    try {
363	      if (req.method === 'GET' && req.url === '/sse') {
364	        const t = new SSEServerTransport('/message', res);
365	        try {
366	          await server.connect(t);
367	          transport = t;
368	          sseConnectedAt = Date.now();
369	          process.stderr.write(`[babysitter] mcp-proxy: SSE connection established\n`);
370	
371	          // Start keepalive pings on the SSE response stream
372	          keepaliveTimer = setInterval(() => {
373	            try {
374	              res.write(':keepalive\n\n');
375	            } catch {
376	              // Stream already closed — timer will be cleared by close handler
377	            }
378	          }, SSE_KEEPALIVE_INTERVAL_MS);
379	
380	          // Log when SSE connection closes (the key diagnostic for the drop)
381	          res.on('close', () => {
382	            const duration = sseConnectedAt ? Date.now() - sseConnectedAt : 0;
383	            sseClosedAt = Date.now();
384	            process.stderr.write(
385	              `[babysitter] mcp-proxy: SSE connection closed after ${duration}ms ` +
386	              `(${toolCallCount} tool calls proxied)\n`,
387	            );
388	            if (keepaliveTimer) {
389	              clearInterval(keepaliveTimer);
390	              keepaliveTimer = null;
391	            }
392	          });
393	
394	          resolveTransport(t);
395	        } catch (err) {
396	          rejectTransport(err instanceof Error ? err : new Error(String(err)));
397	          throw err;
398	        }
399	      } else if (req.method === 'POST' && req.url?.startsWith('/message')) {
400	        if (!transport) {
401	          process.stderr.write(`[babysitter] mcp-proxy: POST /message arrived before SSE transport ready — waiting\n`);
402	        }
403	        let t: SSEServerTransport;
404	        try {
405	          t = await transportReady;
406	        } catch {
407	          res.writeHead(503).end('SSE transport failed to initialize');
408	          return;
409	        }
410	
411	        // Detect and log the "SSE already dead" case before it hits the SDK
412	        if (sseClosedAt) {
413	          const ago = Date.now() - sseClosedAt;
414	          process.stderr.write(
415	            `[babysitter] mcp-proxy: POST /message on dead SSE connection ` +
416	            `(closed ${ago}ms ago, after ${toolCallCount} calls)\n`,
417	          );
418	        }
419	
420	        await t.handlePostMessage(req, res);
421	      } else {
422	        res.writeHead(404).end('Not found');
423	      }
424	    } catch {
425	      if (!res.headersSent) {
426	        res.writeHead(500).end('Internal Server Error');
427	      }
428	    }
429	  });
430	
431	  await new Promise<void>((resolve) => {
432	    httpServer.listen(0, '127.0.0.1', resolve);
433	  });
434	
435	  const addr = httpServer.address();
436	  if (!addr || typeof addr === 'string') {
437	    throw new Error('Failed to get MCP proxy server address');
438	  }
439	
440	  const url = `http://127.0.0.1:${addr.port}/sse`;
441	  process.stderr.write(`[babysitter] MCP proxy server listening on port ${addr.port}\n`);
442	
443	  return {
444	    url,
445	    async close() {
446	      if (keepaliveTimer) {
447	        clearInterval(keepaliveTimer);
448	        keepaliveTimer = null;
449	      }
450	      if (transport) {
451	        await transport.close();
452	      }
453	      await new Promise<void>((resolve, reject) => {
454	        httpServer.close((err) => (err ? reject(err) : resolve()));
455	      });
456	    },
457	  };
458	}
459	
460	// ── SQLite transcript writer ────────────────────────────────────────────
461	
462	/** Minimal interface for the SQLite database used by the babysitter. */
463	export interface TranscriptDb {
464	  /** Write a transcript entry (id, content JSON). */
465	  writeTranscript(sessionId: string, content: string): void;
466	  /** Close the database connection. */
467	  close(): void;
468	}
469	
470	/**
471	 * Open the guild's SQLite database for transcript streaming.
472	 *
473	 * Creates the database file and table if they don't exist.
474	 * Enables WAL mode for concurrent read access by other processes
475	 * (Oculus, CLI queries, other agents).
476	 *
477	 * Uses dynamic import() to load better-sqlite3 at runtime. This avoids
478	 * requiring the native module at import time (beneficial for type-checking
479	 * and testing).
480	 */
481	export async function openTranscriptDb(dbPath: string): Promise<TranscriptDb> {
482	  const { default: Database } = await import('better-sqlite3');
483	  return initTranscriptDb(Database, dbPath);
484	}
485	
486	/**
487	 * Initialize a TranscriptDb from a Database constructor.
488	 *
489	 * Shared logic between openTranscriptDb() and test injection.
490	 * Exported for testing — allows injecting a mock Database constructor.
491	 */
492	export function initTranscriptDb(
493	  DatabaseConstructor: new (path: string) => {
494	    pragma(stmt: string): unknown;
495	    prepare(sql: string): { run(...params: unknown[]): void };
496	    exec(sql: string): void;
497	    close(): void;
498	  },
499	  dbPath: string,
500	): TranscriptDb {
501	  const raw = new DatabaseConstructor(dbPath);
502	  raw.pragma('journal_mode = WAL');
503	  raw.exec(`
504	    CREATE TABLE IF NOT EXISTS books_animator_transcripts (
505	      id      TEXT PRIMARY KEY,
506	      content TEXT NOT NULL
507	    )
508	  `);
509	  const stmt = raw.prepare(
510	    'INSERT OR REPLACE INTO books_animator_transcripts (id, content) VALUES (?, ?)',
511	  );
512	
513	  return {
514	    writeTranscript(sessionId: string, content: string) {
515	      stmt.run(sessionId, content);
516	    },
517	    close() {
518	      raw.close();
519	    },
520	  };
521	}
522	
523	/**
524	 * Write the current transcript to SQLite.
525	 */
526	export function writeTranscript(
527	  db: TranscriptDb,
528	  sessionId: string,
529	  messages: Record<string, unknown>[],
530	): void {
531	  const content = JSON.stringify({ id: sessionId, messages });
532	  db.writeTranscript(sessionId, content);
533	}
534	
535	// ── Session lifecycle reporting ─────────────────────────────────────────
536	
537	/**
538	 * Report "running" status to the guild via the session-running tool.
539	 *
540	 * If the guild is unreachable, writes the payload to the DLQ.
541	 */
542	export async function reportRunning(
543	  config: BabysitterConfig,
544	  cancelHandle: Record<string, unknown>,
545	  timeoutMs?: number,
546	): Promise<void> {
547	  const route = toolNameToRoute('session-running');
548	  const url = `${config.guildToolUrl}${route}`;
549	  const payload = {
550	    sessionId: config.sessionId,
551	    startedAt: config.startedAt,
552	    provider: config.provider,
553	    metadata: config.metadata,
554	    cancelHandle,
555	  };
556	
557	  try {
558	    await callGuildHttpApi(url, config.sessionId, payload, timeoutMs);
559	  } catch {
560	    writeToDlq(config.cwd, `${config.sessionId}-running.json`, payload);
561	  }
562	}
563	
564	/**
565	 * Report the final session result to the guild via the session-record tool.
566	 *
567	 * If the guild is unreachable, writes the payload to the DLQ.
568	 */
569	export async function reportResult(
570	  config: BabysitterConfig,
571	  result: StreamJsonResult,
572	  transcript: Record<string, unknown>[],
573	  timeoutMs?: number,
574	  statusOverride?: 'cancelled',
575	): Promise<void> {
576	  const route = toolNameToRoute('session-record');
577	  const url = `${config.guildToolUrl}${route}`;
578	  const status = statusOverride ?? (result.exitCode === 0 ? 'completed' : 'failed');
579	  const output = extractFinalAssistantText(transcript);
580	
581	  const payload = {
582	    sessionId: config.sessionId,
583	    status,
584	    exitCode: result.exitCode,
585	    signal: result.signal,
586	    error: status === 'failed' ? `claude exited with code ${result.exitCode}` : undefined,
587	    costUsd: result.costUsd,
588	    tokenUsage: result.tokenUsage,
589	    output,
590	    providerSessionId: result.providerSessionId,
591	    transcript,
592	  };
593	
594	  try {
595	    await callGuildHttpApi(url, config.sessionId, payload, timeoutMs);
596	  } catch {
597	    writeToDlq(config.cwd, `${config.sessionId}.json`, payload);
598	  }
599	}
600	
601	// ── Stderr redirect ────────────────────────────────────────────────────
602	
603	/**
604	 * Open a per-session log file and redirect process.stderr.write to it.
605	 *
606	 * Creates the logDir (recursive) and opens `<logDir>/<sessionId>.log`
607	 * for append-writing. Replaces process.stderr.write with a function
608	 * that calls fs.writeSync on the owned fd. Writes the startup banner
609	 * as the first line.
610	 *
611	 * Returns the owned fd so the caller can close it in a finally block.
612	 *
613	 * @internal Exported for testing only.
614	 */
615	export function redirectStderrToFile(logDir: string, sessionId: string): number {
616	  fs.mkdirSync(logDir, { recursive: true });
617	  const logFilePath = path.join(logDir, `${sessionId}.log`);
618	  const fd = fs.openSync(logFilePath, 'a');
619	
620	  // Replace process.stderr.write with a function that writes to our fd.
621	  process.stderr.write = function (
622	    chunk: string | Buffer | Uint8Array,
623	    encodingOrCallback?: BufferEncoding | ((err?: Error) => void),
624	    callback?: (err?: Error) => void,
625	  ): boolean {
626	    const encoding: BufferEncoding =
627	      typeof encodingOrCallback === 'string' ? encodingOrCallback : 'utf8';
628	    const cb = typeof encodingOrCallback === 'function' ? encodingOrCallback : callback;
629	
630	    const buffer = typeof chunk === 'string'
631	      ? Buffer.from(chunk, encoding)
632	      : chunk;
633	    fs.writeSync(fd, buffer);
634	
635	    if (cb) cb();
636	    return true;
637	  } as typeof process.stderr.write;
638	
639	  // Write the startup banner (now goes to the log file).
640	  const pgid = process.getgid?.() ?? process.pid;
641	  process.stderr.write(
642	    `[babysitter] session=${sessionId} pid=${process.pid} pgid=${pgid} log=${logFilePath} started at ${new Date().toISOString()}\n`,
643	  );
644	
645	  return fd;
646	}
647	
648	// ── Main babysitter function ────────────────────────────────────────────
649	
650	/**
651	 * Run the session babysitter.
652	 *
653	 * This is the main orchestration function. It:
654	 * 1. Opens SQLite for transcript streaming
655	 * 2. Starts the MCP proxy server
656	 * 3. Prepares session files (tmpDir, system prompt, mcp-config)
657	 * 4. Spawns claude
658	 * 5. Reports "running" status
659	 * 6. Streams transcript to SQLite
660	 * 7. Reports result on exit
661	 * 8. Cleans up
662	 */
663	export async function runBabysitter(
664	  config: BabysitterConfig,
665	  deps?: {
666	    /** Injected TranscriptDb for testing (avoids loading better-sqlite3). */
667	    db?: TranscriptDb;
668	    /** Override spawn for testing. */
669	    spawnFn?: typeof spawn;
670	    /** Override retry timeout for testing (default: 60_000ms). */
671	    retryTimeoutMs?: number;
672	  },
673	): Promise<void> {
674	  const spawnFn = deps?.spawnFn ?? spawn;
675	  const retryTimeoutMs = deps?.retryTimeoutMs;
676	  let db: TranscriptDb | null = null;
677	  let mcpHandle: McpProxyHandle | null = null;
678	  let tmpDir: string | null = null;
679	  let claudeProc: ChildProcess | null = null;
680	
681	  try {
682	    // 1. Open SQLite
683	    db = deps?.db ?? await openTranscriptDb(config.dbPath);
684	
685	    // 2. Start MCP proxy server
686	    mcpHandle = await createProxyMcpHttpServer(
687	      config.tools,
688	      config.guildToolUrl,
689	      config.sessionId,
690	    );
691	
692	    // 3. Prepare session files
693	    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'nsg-babysitter-'));
694	
695	    const args = [...config.claudeArgs];
696	
697	    // Write system prompt if present in args (already handled by claudeArgs)
698	    // Write mcp-config pointing to the babysitter's MCP proxy server
699	    const mcpConfig = {
700	      mcpServers: {
701	        'nexus-guild': {
702	          type: 'sse',
703	          url: mcpHandle.url,
704	        },
705	      },
706	    };
707	    const mcpConfigPath = path.join(tmpDir, 'mcp-config.json');
708	    fs.writeFileSync(mcpConfigPath, JSON.stringify(mcpConfig));
709	    args.push('--mcp-config', mcpConfigPath, '--strict-mcp-config');
710	
711	    // Add autonomous mode flags
712	    args.push(
713	      '--print', '-',
714	      '--output-format', 'stream-json',
715	      '--verbose',
716	    );
717	
718	    // 4. Spawn claude
719	    claudeProc = spawnFn('claude', args, {
720	      cwd: config.cwd,
721	      stdio: ['pipe', 'pipe', 'pipe'],
722	      env: { ...process.env, ...config.env },
723	    });
724	
725	    // Pipe prompt to claude's stdin, then close
726	    if (config.prompt) {
727	      claudeProc.stdin!.write(config.prompt);
728	    }
729	    claudeProc.stdin!.end();
730	
731	    // Forward claude's stderr through the babysitter's redirected stderr
732	    claudeProc.stderr?.on('data', (chunk: Buffer) => {
733	      process.stderr.write(chunk);
734	    });
735	
736	    // 5. Report "running" status (don't await — fire and forget with retry)
737	    const cancelHandle = { kind: 'local-pgid' as const, pgid: process.pid };
738	    const runningPromise = reportRunning(config, cancelHandle, retryTimeoutMs).catch((err) => {
739	      process.stderr.write(`[babysitter] Failed to report running: ${err}\n`);
740	    });
741	
742	    // 5b. Heartbeat timer — sends liveness signal every 30s after ready report.
743	    const HEARTBEAT_INTERVAL_MS = 30_000;
744	    const HEARTBEAT_TIMEOUT_MS = 10_000;
745	    let heartbeatTimer: ReturnType<typeof setTimeout> | null = null;
746	
747	    function scheduleHeartbeat() {
748	      heartbeatTimer = setTimeout(async () => {
749	        const route = toolNameToRoute('session-heartbeat');
750	        const hbUrl = `${config.guildToolUrl}${route}`;
751	        try {
752	          await callGuildHttpApi(hbUrl, config.sessionId, { sessionId: config.sessionId }, HEARTBEAT_TIMEOUT_MS);
753	        } catch {
754	          // Dropped — next heartbeat in 30s. Staleness threshold (90s) tolerates this.
755	        }
756	        scheduleHeartbeat();
757	      }, HEARTBEAT_INTERVAL_MS);
758	    }
759	
760	    // Start heartbeat after running report completes
761	    runningPromise.then(() => scheduleHeartbeat());
762	
763	    // 5c. SIGTERM handler — sets cancelled flag and propagates to claude.
764	    let cancelledBySignal = false;
765	
766	    const onSigterm = () => {
767	      cancelledBySignal = true;
768	      // Stop heartbeat timer
769	      if (heartbeatTimer) {
770	        clearTimeout(heartbeatTimer);
771	        heartbeatTimer = null;
772	      }
773	      // Propagate SIGTERM to the claude process
774	      if (claudeProc && claudeProc.pid && !claudeProc.killed) {
775	        try {
776	          claudeProc.kill('SIGTERM');
777	        } catch { /* already dead */ }
778	      }
779	      // The normal claude exit path will run, check cancelledBySignal,
780	      // and report status 'cancelled' instead of computing from exit code.
781	    };
782	
783	    process.on('SIGTERM', onSigterm);
784	
785	    // 6. Consume stdout, stream transcript
786	    const acc: {
787	      transcript: Record<string, unknown>[];
788	      costUsd?: number;
789	      tokenUsage?: StreamJsonResult['tokenUsage'];
790	      providerSessionId?: string;
791	    } = { transcript: [] };
792	
793	    let buffer = '';
794	
795	    claudeProc.stdout!.on('data', (chunk: Buffer) => {
796	      buffer += chunk.toString();
797	      const prevLength = acc.transcript.length;
798	      buffer = processNdjsonBuffer(buffer, (msg) => {
799	        parseStreamJsonMessage(msg, acc);
800	      });
801	
802	      // Write transcript to SQLite if new messages were added
803	      if (acc.transcript.length > prevLength && db) {
804	        writeTranscript(db, config.sessionId, acc.transcript);
805	      }
806	    });
807	
808	    // 7. Wait for claude to exit
809	    const { code: exitCode, signal: exitSignal } = await new Promise<{ code: number; signal: string | undefined }>((resolve, reject) => {
810	      claudeProc!.on('error', (err) => {
811	        reject(new Error(`Failed to spawn claude: ${err.message}`));
812	      });
813	      claudeProc!.on('close', (code, signal) => {
814	        resolve({ code: code ?? 1, signal: signal ?? undefined });
815	      });
816	    });
817	
818	    // Stop heartbeat before terminal report
819	    if (heartbeatTimer) {
820	      clearTimeout(heartbeatTimer);
821	      heartbeatTimer = null;
822	    }
823	
824	    // Clean up SIGTERM handler
825	    process.removeListener('SIGTERM', onSigterm);
826	
827	    // Ensure running report completed before recording result
828	    await runningPromise;
829	
830	    // Build result
831	    const result: StreamJsonResult = {
832	      exitCode,
833	      transcript: acc.transcript,
834	      costUsd: acc.costUsd,
835	      tokenUsage: acc.tokenUsage,
836	      providerSessionId: acc.providerSessionId,
837	      signal: exitSignal,
838	    };
839	
840	    // 8. Report result
841	    await reportResult(config, result, acc.transcript, retryTimeoutMs, cancelledBySignal ? 'cancelled' : undefined);
842	  } catch (err) {
843	    // Top-level error: attempt to report failure
844	    const message = err instanceof Error ? err.message : String(err);
845	
846	    try {
847	      const route = toolNameToRoute('session-record');
848	      const url = `${config.guildToolUrl}${route}`;
849	      await callGuildHttpApi(url, config.sessionId, {
850	        sessionId: config.sessionId,
851	        status: 'failed',
852	        exitCode: 1,
853	        error: message,
854	      }, retryTimeoutMs);
855	    } catch {
856	      writeToDlq(config.cwd, `${config.sessionId}.json`, {
857	        sessionId: config.sessionId,
858	        status: 'failed',
859	        exitCode: 1,
860	        error: message,
861	      });
862	    }
863	
864	    throw err;
865	  } finally {
866	    // 9. Cleanup
867	    process.removeAllListeners('SIGTERM');
868	    await mcpHandle?.close().catch(() => {});
869	    db?.close();
870	    if (tmpDir) {
871	      fs.rmSync(tmpDir, { recursive: true, force: true });
872	    }
873	    if (config.systemPromptTmpDir) {
874	      fs.rmSync(config.systemPromptTmpDir, { recursive: true, force: true });
875	    }
876	  }
877	}
878	
879	// ── Entry point ─────────────────────────────────────────────────────────
880	
881	/**
882	 * Script entry point — reads config from stdin and runs the babysitter.
883	 *
884	 * Only executes when this file is run directly (not when imported).
885	 */
886	async function main(): Promise<void> {
887	  let fd: number | undefined;
888	  try {
889	    const config = await readConfigFromStdin();
890	    fd = redirectStderrToFile(config.logDir, config.sessionId);
891	    await runBabysitter(config);
892	    process.exit(0);
893	  } catch (err) {
894	    process.stderr.write(
895	      `[babysitter] Fatal error: ${err instanceof Error ? err.message : String(err)}\n`,
896	    );
897	    process.exit(1);
898	  } finally {
899	    if (fd !== undefined) {
900	      try { fs.closeSync(fd); } catch { /* already closed */ }
901	    }
902	  }
903	}
904	
905	// Check if this module is the entry point
906	const isEntryPoint = process.argv[1] &&
907	  (process.argv[1] === fileURLToPath(import.meta.url) ||
908	   path.basename(process.argv[1]) === 'babysitter.js' ||
909	   path.basename(process.argv[1]) === 'babysitter.ts');
910	
911	if (isEntryPoint) {
912	  main();
913	}
