 */
const pendingPriorBlocks = new Map<string, BlockRecord>();

/**
 * In-memory queue of pending grafts.
 * Key: rigId. Value: { engineId, graft, writId }.
 * Written by tryCollect/tryRun when a completed engine has a graft.
 * Consumed by tryProcessGrafts.
 */
const pendingGrafts = new Map<string, { engineId: string; graft: RigTemplateEngine[]; writId: string; graftTail?: string }>();

// ── Internal crawl operations ─────────────────────────────────────

/**
 * Mark an engine failed and propagate to the rig as `stuck` (same update).
 * The failed engine itself transitions to `failed`; pending/blocked engines
 * are cancelled. The rig enters `stuck` — a non-terminal "needs attention"
 * state that preserves the obligation for future retry.
 */
async function failEngine(
  rig: RigDoc,
  engineId: string,
  errorMessage: string,
): Promise<void> {
  const now = new Date().toISOString();
  const updatedEngines = rig.engines.map((e) => {
    if (e.id === engineId) {
      return { ...e, status: 'failed' as const, error: errorMessage, completedAt: now };
    }
    if (e.status === 'pending' || e.status === 'blocked') {
      return { ...e, status: 'cancelled' as const, block: undefined };
    }
    return e;
  });
  await rigsBook.patch(rig.id, {
    engines: updatedEngines,
    status: 'stuck',
  });
}

/**
 * Mark an engine cancelled and propagate cancellation to the rig (same update).
 * Cancels all pending and blocked engines. Does NOT call Animator.cancel() —
 * that is the caller's responsibility.
 */
async function cancelEngine(
  rig: RigDoc,
  engineId: string,
  reason?: string,
): Promise<void> {
  const now = new Date().toISOString();
  const updatedEngines = rig.engines.map((e) => {
    if (e.id === engineId) {
      return { ...e, status: 'cancelled' as const, error: reason ?? undefined, completedAt: now, block: undefined };
    }
    if (e.status === 'pending' || e.status === 'blocked') {
      return { ...e, status: 'cancelled' as const, block: undefined };
    }
    return e;
  });
  await rigsBook.patch(rig.id, {
    engines: updatedEngines,
    status: 'cancelled',
  });
}

/**
 * Reject all pending input requests for a rig.
 */
async function rejectPendingInputRequests(rigId: string): Promise<void> {
  const pendingRequests = await inputRequestsBook.find({
    where: [['rigId', '=', rigId], ['status', '=', 'pending']],
  });
  const now = new Date().toISOString();
  for (const req of pendingRequests) {
    await inputRequestsBook.patch(req.id, {
      status: 'rejected',
      rejectionReason: 'Rig cancelled',
      updatedAt: now,
    });
  }
}

/**
 * Phase 1 — collect.
 *
 * Find the first running engine with a sessionId whose session has
 * reached a terminal state. Populate yields and advance the engine
 * (and possibly the rig) to completed or failed.
 *
 * After collecting a completed engine, check whether the rig has
 * become blocked (no running engines, no runnable engines, some blocked).
 */
async function tryCollect(): Promise<CrawlResult | null> {
  const runningRigs = await rigsBook.find({ where: [['status', '=', 'running']] });
  for (const rig of runningRigs) {
    for (const engine of rig.engines) {
      if (engine.status !== 'running' || !engine.sessionId) continue;

      const session = await sessionsBook.get(engine.sessionId);
      // Both 'pending' and 'running' are non-terminal — keep waiting.
      // 'pending' was added when launchDetached started pre-writing the
      // SessionDoc before spawning the babysitter; without this check we
      // would treat freshly-pre-written sessions as already-completed and
      // mark engines done with no actual work performed.
      if (!session || session.status === 'running' || session.status === 'pending') continue;

      // Terminal session found — collect.
      const now = new Date().toISOString();

      if (session.status === 'failed' || session.status === 'timeout') {
        await failEngine(rig, engine.id, session.error ?? `Session ${session.status}`);
        return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'stuck' };
      }

      if (session.status === 'cancelled') {
        await cancelEngine(rig, engine.id, session.error ?? 'Session cancelled');
        await rejectPendingInputRequests(rig.id);
        return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'cancelled' };
      }

/**
 * The Spider — public types.
 *
 * Rig and engine data model, CrawlResult, SpiderApi, and configuration.
 * Engine yield shapes (DraftYields, SealYields) live here too so downstream
 * packages can import them without depending on the engine implementation files.
 */

import type { ZodSchema } from 'zod';

// ── Engine instance status ────────────────────────────────────────────

export type EngineStatus = 'pending' | 'running' | 'completed' | 'failed' | 'cancelled' | 'blocked' | 'skipped';

// ── Block record ──────────────────────────────────────────────────────

/**
 * Persisted record of an active engine block.
 * Present on an EngineInstance when status === 'blocked'.
 * Cleared when the block is resolved.
 */
export interface BlockRecord {
  /** Block type identifier (matches a registered BlockType.id). */
  type: string;
  /** Structured condition payload — shape validated by the block type's conditionSchema. */
  condition: unknown;
  /** ISO timestamp when the engine was blocked. */
  blockedAt: string;
  /** Optional human-readable message from the engine. */
  message?: string;
  /** ISO timestamp of the last checker evaluation. Updated on every check cycle. */
  lastCheckedAt?: string;
}

// ── Engine instance ───────────────────────────────────────────────────

/**
 * A single engine slot within a rig.
 *
 * `id` is the engine's position identifier (e.g. 'draft', 'implement').
 * For the static pipeline it matches `designId`.
 *
 * `givensSpec` holds values set at spawn time (writ, role, commands) and
 * may contain unresolved yield expression strings (`${yields.<id>.<path>}`)
 * that the Spider resolves at run time from upstream engine yields.
 */
export interface EngineInstance {
  /** Unique identifier within the rig (e.g. 'draft', 'implement'). */
  id: string;
  /** The engine design to look up in the Fabricator. */
  designId: string;
  /** Current execution status. */
  status: EngineStatus;
  /** Engine IDs that must be completed before this engine can run. */
  upstream: string[];
  /**
   * Givens values. Spawn-time expressions (`${writ}`, `${writ.*}`, `${vars.*}`)
   * are resolved to their values. Yield expressions (`${yields.*}`) remain as
   * literal `${yields.*}` strings and are resolved at run time when the engine
   * is executed.
   */
  givensSpec: Record<string, unknown>;
  /**
   * Conditional activation expression, copied from the template.
   * Evaluated at runtime when upstream is all done. Absent means unconditional.
   */
  when?: string;
  /** Yields from a completed engine run (JSON-serializable). */
  yields?: unknown;
  /** Error message if this engine failed. */
  error?: string;
  /** Session ID from a launched quick engine, used by the collect step. */
  sessionId?: string;
  /** ISO timestamp when execution started. */
  startedAt?: string;
  /** ISO timestamp when execution completed (or failed). */
  completedAt?: string;
  /** Present when status === 'blocked'. Cleared when the block is resolved. */
  block?: BlockRecord;
}

// ── Rig ──────────────────────────────────────────────────────────────

export type RigStatus = 'running' | 'stuck' | 'completed' | 'failed' | 'cancelled' | 'blocked';

/**
 * A rig — the execution context for a single writ.
 *
 * Stored in The Stacks (`spider/rigs` book). The `engines` array is the
 * ordered pipeline of engine instances. The Spider updates this document
 * in-place as engines run and complete.
 */
export interface RigDoc {
  /** Index signature required to satisfy BookEntry constraint. */
  [key: string]: unknown;
  /** Unique rig id. */
  id: string;
  /** The writ this rig is executing. */
  writId: string;
  /** Current rig status. */
  status: RigStatus;
  /** Ordered engine pipeline. */
  engines: EngineInstance[];
  /** ISO timestamp when the rig was created. */
  createdAt: string;
  /** Engine id whose yields provide the resolution summary. Set at spawn time. */
  resolutionEngineId?: string;
}

// ── Rig filters ───────────────────────────────────────────────────────

/**
 * Filters for listing rigs.
 */
export interface RigFilters {
  /** Filter by rig status. */
  status?: RigStatus;
  /** Maximum number of results (default: 20). */
  limit?: number;
  /** Number of results to skip. */
  offset?: number;
}

// ── Rig templates ─────────────────────────────────────────────────────

/**
 * A single engine slot declared in a rig template.
 */
export interface RigTemplateEngine {
  /** Engine id unique within this template. */
  id: string;
  /** Engine design id to look up in the Fabricator. */
  designId: string;
  /** Engine ids within this template whose completion is required first. Defaults to []. */
  upstream?: string[];
  /**
   * Givens to pass to the engine.
   *
   * String values may contain `${...}` template expressions:
   *   `${writ}` — the full WritDoc for this rig's writ
   *   `${writ.<path>}` — a field of the WritDoc (dot-path traversal)
   *   `${vars.<path>}` — value from spider.variables config (dot-path traversal)
   *   `${yields.<engine_id>.<path>}` — a property from an upstream engine's
   *       yields (resolved at run time, dot-path traversal)
   *
   * When a string is exactly one expression (e.g. `${writ}`), the resolved
   * value preserves its original type. When expressions are embedded in a
   * larger string, the result is always a string.
   *
   * Non-string values are passed through literally.
   * Whole-value expressions that resolve to undefined cause the key to be omitted.
   * Inline expressions that resolve to undefined are replaced with empty string.
   *
   * Use `\${` to produce a literal `${` in the output without interpolation.
   */
  givens?: Record<string, unknown>;
  /**
   * Conditional activation expression. A `${yields.<engine_id>.<property>}` reference
   * (with optional `!` negation prefix) evaluated at runtime when the engine's upstream
   * is all done. When the condition is falsy, the engine is set to `skipped` status.
   * When absent, the engine is unconditional (always runs).
   *
   * Examples:
   *   '${yields.review.passed}'  — run this engine when review.passed is truthy
   *   '!${yields.review.passed}' — run this engine when review.passed is falsy
   */
  when?: string;
}

/**
 * A complete rig template.
 */
export interface RigTemplate {
  /** Ordered list of engine slot declarations. */
  engines: RigTemplateEngine[];
  /**
   * Engine id whose yields provide the writ resolution summary.
   * Falls back to seal engine, then last completed engine in array order.
   */
  resolutionEngine?: string;
}

// ── CrawlResult ────────────────────────────────────────────────────────

/**
 * The result of a single crawl() call.
 *
 * Variants, ordered by priority:
 * - 'engine-completed'  — an engine finished (collected or ran inline); rig still running
 * - 'engine-started'    — launched a quick engine's session
 * - 'engine-blocked'    — engine entered blocked status; rig is still running (other engines active)
 * - 'engine-unblocked'  — a blocked engine's condition cleared; engine returned to pending
 * - 'rig-spawned'       — created a new rig for a ready writ
 * - 'rig-completed'     — the crawl step caused a rig to reach a terminal state
 * - 'rig-blocked'       — all forward progress stalled; rig entered blocked status
 * - 'gated'             — an open writ's dispatch is gated on outbound
 *                         spider.follows links that point at non-terminal
 *                         blockers; no rig was spawned and no status was
 *                         written (gate-only state is never persisted).
 * - 'writ-unstuck'      — a writ that Spider previously stuck via the gating

// ── Spider-extended engine run / collect result types ─────────────────

/**
 * Spider-extended engine run result. Adds an optional `graft` field
 * to the `completed` variant, allowing engines to dynamically append
 * new engines to the rig alongside their yields.
 *
 * Engines that want to graft import this type from @shardworks/spider-apparatus.
 * Engines that don't graft use the base EngineRunResult from @shardworks/fabricator-apparatus.
 *
 * The Spider internally checks for the `graft` property on any completed result
 * (duck-typing — the Fabricator type is not modified).
 */
export type SpiderEngineRunResult =
  | { status: 'completed'; yields: unknown; graft?: RigTemplateEngine[]; graftTail?: string }
  | { status: 'launched'; sessionId: string }
  | { status: 'blocked'; blockType: string; condition: unknown; message?: string };

/**
 * Spider-extended collect result. When a quick engine's collect() method
 * returns an object with a `graft` property (an array), the Spider extracts
 * it as a graft request and uses the `yields` property as the engine's yields.
 *
 * When collect() returns a value without a `graft` array property, the entire
 * return value is treated as yields (backward compatible).
 */
export interface SpiderCollectResult {
  yields: unknown;
  graft?: RigTemplateEngine[];
  graftTail?: string;
}

// ── status.spider sub-slot shape ────────────────────────────────────────

/**
 * The reason a writ is stuck in Spider's gating machinery.
 *
 * - 'failed-blocker' — at least one outbound `spider.follows` blocker
 *                      reached `failed`; the dependent was cascaded to
 *                      `stuck` directly (not transitively).
 * - 'cycle'          — a back-edge was discovered in the `spider.follows`
 *                      graph during gate evaluation; every cycle member is
 *                      stuck with this cause.
 */
export type SpiderStuckCause = 'failed-blocker' | 'cycle';

/**
 * Shape of the plugin-owned `status.spider` sub-slot as written by the
 * Spider's gating paths.
 *
 * The slot is absent (not the empty object) on writs Spider has never
 * touched. It is **also** absent on writs that reached `stuck` via the
 * pre-existing engine-cascade path (rig → writ CDC handler) — absence is
 * the load-bearing signal that tells `autoUnstick` not to revisit those
 * writs.
 *
 * The slot is written only on stuck transitions and cleared on
 * auto-unstick. Nothing is written while a writ is gated-but-not-stuck.
 */
export interface SpiderWritStatus {
  /** Present only while the writ is stuck for a gating reason. */
  stuckCause?: SpiderStuckCause;
  /**
   * The blockers responsible for the stuck transition. For
   * `failed-blocker`, these are the outbound `spider.follows` targets that
   * reached `failed`. For `cycle`, these are the members of the detected
   * cycle (typically including the dependent itself).
   */
  blockerIds?: string[];
  /** ISO timestamp recorded at the moment the stuck transition was taken. */
  observedAt?: string;
}

// Augment GuildConfig so `guild().guildConfig().spider` is typed.
declare module '@shardworks/nexus-core' {
  interface GuildConfig {
    spider?: SpiderConfig;
  }
}

/**
 * Clerk public types.
 *
 * All types exported from @shardworks/clerk-apparatus.
 */

// ── Writ phase ───────────────────────────────────────────────────────

/**
 * A writ's position in its lifecycle.
 *
 * Transitions:
 *   new    → open       (publish)   — draft enters the queue
 *   new    → cancelled  (cancel)
 *   open   → completed  (complete)
 *   open   → failed     (fail)
 *   open   → cancelled  (cancel)
 *   open   → stuck      (engine failure cascade)
 *   stuck  → open       (recovery/retry resumes execution)
 *   stuck  → failed     (obligation abandoned)
 *   stuck  → cancelled  (obligation withdrawn)
 *
 * completed, failed, cancelled are terminal — no further transitions.
 * stuck is non-terminal — it represents a "needs attention" state.
 */
export type WritPhase = 'new' | 'open' | 'stuck' | 'completed' | 'failed' | 'cancelled';

// ── Documents ────────────────────────────────────────────────────────

/**
 * A writ document as stored in The Stacks.
 */
export interface WritDoc {
  /** Index signature required to satisfy BookEntry constraint. */
  [key: string]: unknown;
  /** Unique writ id (`w-{base36_timestamp}{hex_random}`). Sortable by creation time. */
  id: string;
  /** Writ type — must be a type declared in guild config, or a built-in type. */
  type: string;
  /** Current lifecycle phase (Clerk-owned; spec side of the spec/status split). */
  phase: WritPhase;
  /**
   * Plugin-owned observation slot (status side of the spec/status split).
   *
   * The observation slot is a plugin-keyed map (`Record<PluginId,
   * unknown>`): each top-level key is a plugin id, and the value is an
   * arbitrary shape that plugin publishes for post-hoc observation.
   * Ownership is convention-only — plugin `X` writes only to `status[X]`.
   *
   * There is exactly one sanctioned slot-write path:
   * `ClerkApi.setWritStatus(writId, pluginId, value)`, which performs a
   * transactional read-modify-write on the sub-slot keyed by `pluginId`
   * so sibling sub-slots are preserved under concurrent writers.
   * `transition()` silently strips `status` from its body, and the
   * generic `put()` / `patch()` paths on the writs book are not
   * supported slot-write mechanisms — every route other than
   * `setWritStatus()` would wholesale-replace the slot and clobber
   * sibling sub-slots. Readers access `writ.status?.[pluginId]` directly.
   *
   * The slot survives terminal phase transitions.
   */
  status?: Record<string, unknown>;
  /** Short human-readable title. */
  title: string;
  /** Detail text. */
  body: string;
  /** Target codex name. */
  codex?: string;
  /** Parent writ id. Absent on root writs. Immutable after creation. */
  parentId?: string;
  /** ISO timestamp when the writ was created. */
  createdAt: string;
  /** ISO timestamp of the last mutation. */
  updatedAt: string;
  /** ISO timestamp when the writ reached a terminal state. */
  resolvedAt?: string;
  /** Summary of how the writ resolved (set on any terminal transition). */
  resolution?: string;
}

// ── Requests ─────────────────────────────────────────────────────────

/**
 * Request to post a new commission (create a writ).
 */
/**
 * Request to edit a writ. Title and body can be edited in any status.
 * Type and codex can only be changed while the writ is in 'new' status.
 * All fields are optional — only provided fields are updated.
 */
export interface EditWritRequest {
  /** Writ id. */
  id: string;
  /** New title. */
  title?: string;
  /** New body text. */
  body?: string;
  /** New writ type. Must be a valid declared type. */
  type?: string;
  /** New target codex name. Pass empty string to clear. */

