2033	        }
2034	        if (!allResolved) continue;
2035	      } else if (cause === 'cycle') {
2036	        // Release if any cycle member has moved out of `open` — the
2037	        // cycle can only persist while every member is still open.
2038	        let brokenByAnyMember = false;
2039	        for (const memberId of blockerIds) {
2040	          const member = await writsBook.get(memberId);
2041	          if (!member) {
2042	            brokenByAnyMember = true;
2043	            break;
2044	          }
2045	          if (member.id === writ.id) continue; // self is currently stuck
2046	          if (member.phase !== 'open' && member.phase !== 'stuck') {
2047	            brokenByAnyMember = true;
